import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class ScratchPad {

    public static void main(String[] args) {
        Solution solution = new Solution();
        String[] words = {"cat", "rat", "mat", "tab", "bat", "car", "race","aaxaab","b"};
        List<List<Integer>> palindromePairs = solution.palindromePairs(words);

        for (List<Integer> pair : palindromePairs) {
            System.out.println(words[pair.get(0)] + " + " + words[pair.get(1)] + " -> Palindrome");
        }
    }

    static class Solution {
        public List<List<Integer>> palindromePairs(String[] words) {
            List<List<Integer>> pairs = new ArrayList<>();
            for (int i = 0; i < words.length; i++) {
                for (int j = 0; j < words.length; j++) {
                    if (i != j && isPalindrome(words[i], words[j])) {
                        pairs.add(Arrays.asList(i, j));
                    }
                }
            }
            return pairs;
        }

        private boolean isPalindrome(String word1, String word2) {
            String combined = word1.concat(word2);
            int left = 0, right = combined.length() - 1;
            while (left < right) {
                if (combined.charAt(left++) != combined.charAt(right--)) {
                    return false;
                }
            }
            return true;
        }
    }
}



Optimization using Trie:

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Arrays;

public class ScratchPad {

    static class TrieNode {
        int wordEnding = -1; // -1 indicates no word ending here
        Map<Character, TrieNode> next = new HashMap<>();
        List<Integer> palindromePrefixRemaining = new ArrayList<>();
    }

    static class Solution {

        private boolean hasPalindromeRemaining(String s, int index) {
            int left = index, right = s.length() - 1;
            while (left < right) {
                if (s.charAt(left++) != s.charAt(right--)) {
                    return false;
                }
            }
            return true;
        }

        public List<List<Integer>> palindromePairs(String[] words) {
            TrieNode root = new TrieNode();
            buildTrie(words, root);

            List<List<Integer>> pairs = new ArrayList<>();
            for (int i = 0; i < words.length; i++) {
                search(words, i, root, pairs);
            }
            return pairs;
        }

        private void buildTrie(String[] words, TrieNode root) {
            for (int wordId = 0; wordId < words.length; wordId++) {
                String word = new StringBuilder(words[wordId]).reverse().toString();
                TrieNode node = root;
                for (int j = 0; j < word.length(); j++) {
                    if (hasPalindromeRemaining(word, j)) {
                        node.palindromePrefixRemaining.add(wordId);
                    }
                    char c = word.charAt(j);
                    if (!node.next.containsKey(c)) {
                        node.next.put(c, new TrieNode());
                    }
                    node = node.next.get(c);
                }
                node.wordEnding = wordId;
            }
        }

        private void search(String[] words, int wordId, TrieNode root, List<List<Integer>> pairs) {
            TrieNode node = root;
            for (int j = 0; j < words[wordId].length(); j++) {
                if (node.wordEnding != -1 && hasPalindromeRemaining(words[wordId], j)) {
                    pairs.add(Arrays.asList(wordId, node.wordEnding));
                }
                node = node.next.get(words[wordId].charAt(j));
                if (node == null) return;
            }
            if (node.wordEnding != -1 && node.wordEnding != wordId) {
                pairs.add(Arrays.asList(wordId, node.wordEnding));
            }
            for (int other : node.palindromePrefixRemaining) {
                pairs.add(Arrays.asList(wordId, other));
            }
        }
    }

    public static void main(String[] args) {
        Solution solution = new Solution();
        String[] words = {"cat", "rat", "mat", "tab", "bat", "car", "race","aaxaab","b"};
        List<List<Integer>> palindromePairs = solution.palindromePairs(words);

        for (List<Integer> pair : palindromePairs) {
            System.out.println(words[pair.get(0)] + " + " + words[pair.get(1)] + " -> Palindrome");
        }
    }
}


